import { cfg } from "../lib/config.js";
import { safeErr } from "../lib/log.js";

async function fetchJson(url, options = {}, meta = {}) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 20000);
  try {
    console.log("[api] start", meta);
    const res = await fetch(url, { ...options, signal: controller.signal });
    const text = await res.text();
    let json = null;
    try {
      json = JSON.parse(text);
    } catch {
      json = null;
    }
    if (!res.ok) throw new Error(json?.message || json?.error || text || `HTTP ${res.status}`);
    console.log("[api] success", meta);
    return { ok: true, json, text };
  } catch (err) {
    console.warn("[api] failure", { ...meta, error: safeErr(err) });
    return { ok: false, error: safeErr(err) };
  } finally {
    clearTimeout(timer);
  }
}

export async function getNativeBalance(address) {
  if (!cfg.CHAIN_RPC_URL || !address) {
    return { ok: false, partial: true, balance: "unknown", error: "RPC unavailable" };
  }

  const res = await fetchJson(cfg.CHAIN_RPC_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ jsonrpc: "2.0", id: 1, method: "eth_getBalance", params: [address, "latest"] })
  }, { feature: "balance", provider: "rpc", chainId: cfg.CHAIN_ID });

  if (!res.ok || !res.json?.result) return { ok: false, partial: true, balance: "unknown", error: res.error || "RPC unavailable" };
  const wei = BigInt(res.json.result);
  const native = Number(wei) / 1e18;
  return { ok: true, balance: native.toFixed(6) };
}

export async function getQuote({ side, tokenAddress, amount, slippage, walletAddress }) {
  if (!cfg.DEX_AGGREGATOR_API_URL) {
    console.warn("[api] quote gated", { feature: "quote", DEX_AGGREGATOR_API_URL_set: false });
    return { ok: false, gated: true, estimatedOutput: "unavailable", estimatedGas: "unavailable", error: "Quote API unavailable" };
  }

  const base = cfg.DEX_AGGREGATOR_API_URL.replace(/\/+$/, "");
  const url = new URL(`${base}/quote`);
  url.searchParams.set("chainId", String(cfg.CHAIN_ID));
  url.searchParams.set("side", String(side));
  url.searchParams.set("token", String(tokenAddress));
  url.searchParams.set("amount", String(amount));
  url.searchParams.set("slippage", String(slippage));
  if (walletAddress) url.searchParams.set("wallet", String(walletAddress));

  const res = await fetchJson(url.toString(), {}, { feature: "quote", provider: "dex", side, chainId: cfg.CHAIN_ID });
  if (!res.ok) return { ok: false, estimatedOutput: "unavailable", estimatedGas: "unavailable", error: res.error };

  const q = res.json || {};
  return {
    ok: true,
    estimatedOutput: q.estimatedOutput || q.outAmount || q.outputAmount || "unknown",
    estimatedGas: q.estimatedGas || q.gas || "unknown",
    priceImpact: q.priceImpact || "unknown",
    raw: q
  };
}

export async function getTokenRisk(tokenAddress) {
  if (!cfg.DEX_AGGREGATOR_API_URL) {
    return {
      ok: false,
      flags: ["Risk data unavailable", "Liquidity data unavailable"],
      liquidityWarning: true,
      riskyWarning: true
    };
  }

  const base = cfg.DEX_AGGREGATOR_API_URL.replace(/\/+$/, "");
  const url = new URL(`${base}/risk`);
  url.searchParams.set("chainId", String(cfg.CHAIN_ID));
  url.searchParams.set("token", String(tokenAddress));

  const res = await fetchJson(url.toString(), {}, { feature: "risk", provider: "dex", chainId: cfg.CHAIN_ID });
  if (!res.ok) {
    return { ok: false, flags: ["Risk data unavailable"], liquidityWarning: true, riskyWarning: true };
  }

  const r = res.json || {};
  const flags = Array.isArray(r.flags) ? r.flags : [];
  const liquidity = Number(r.liquidityUsd || r.liquidity || 0);
  if (!Number.isFinite(liquidity) || liquidity < 10000) flags.push("Low or unknown liquidity");
  if (r.honeypot || r.highTax || r.ownerRisk) flags.push("Suspicious token checks");

  return {
    ok: true,
    flags,
    liquidityWarning: !Number.isFinite(liquidity) || liquidity < 10000,
    riskyWarning: flags.length > 0,
    liquidityUsd: liquidity || null,
    symbol: r.symbol || "TOKEN"
  };
}

export async function getTokenPrice(tokenAddress) {
  if (!cfg.PRICE_API_URL) {
    return { ok: false, price: null, error: "Price API unavailable" };
  }

  const base = cfg.PRICE_API_URL.replace(/\/+$/, "");
  const url = new URL(`${base}/price`);
  url.searchParams.set("chainId", String(cfg.CHAIN_ID));
  url.searchParams.set("token", String(tokenAddress));

  const res = await fetchJson(url.toString(), {}, { feature: "price", provider: "price", chainId: cfg.CHAIN_ID });
  if (!res.ok) return { ok: false, price: null, error: res.error };
  return { ok: true, price: Number(res.json?.price || 0) || null, symbol: res.json?.symbol || "TOKEN" };
}

export async function submitSwap({ trade, wallet }) {
  if (!cfg.CHAIN_RPC_URL || !cfg.DEX_AGGREGATOR_API_URL) {
    return { ok: false, gated: true, error: "Live trading is disabled until RPC and DEX aggregator are configured." };
  }

  if (!wallet?.encryptedSecret) {
    return { ok: false, gated: true, error: "This wallet is watch-only. Import or create a signing wallet to trade." };
  }

  console.log("[api] start", { feature: "swap", provider: "dex", side: trade.side, chainId: cfg.CHAIN_ID });
  console.warn("[api] failure", { feature: "swap", provider: "dex", error: "Execution adapter not connected" });
  return { ok: false, error: "Execution adapter is not connected yet. Quote and safety checks are available." };
}

risk.js.content:
import { getTokenRisk } from "./chain.js";

export async function buildRiskSummary({ user, tokenAddress, amount, side }) {
  const settings = user?.settings || {};
  const flags = [];
  const hardBlocks = [];

  const amountNum = Number(amount || 0);
  const maxPercent = Number(settings.maxPercentPerTrade || 20);
  const bigBuy = Number(settings.bigBuyConfirmThreshold || 1);

  if (!Number.isFinite(amountNum) || amountNum <= 0) hardBlocks.push("Invalid amount");
  if (side === "buy" && amountNum > bigBuy) flags.push("Big buy confirmation required");

  const tokenRisk = await getTokenRisk(tokenAddress);
  for (const flag of tokenRisk.flags || []) flags.push(flag);

  if (maxPercent <= 0 || maxPercent > 100) flags.push("Max percent setting is unusual");

  return {
    flags: [...new Set(flags)],
    hardBlocks,
    liquidityWarning: Boolean(tokenRisk.liquidityWarning),
    riskyWarning: Boolean(tokenRisk.riskyWarning),
    requiresExtraConfirm: flags.length > 0 || (side === "buy" && amountNum > bigBuy),
    exceedsMaxPercent: false,
    maxPercentPerTrade: maxPercent,
    symbol: tokenRisk.symbol || "TOKEN",
    liquidityUsd: tokenRisk.liquidityUsd || null
  };
}

snipes.js.content:
import { cfg } from "../lib/config.js";
import { safeErr } from "../lib/log.js";
import { listActiveSnipes, updateSnipe } from "./store.js";
import { getTokenRisk } from "./chain.js";

let running = false;
let timer = null;
let cycle = 0;
let lastMemLog = 0;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function monitorLoop() {
  console.log("[snipes] poll started", { pollMs: cfg.SNIPE_POLL_MS });
  while (running) {
    cycle += 1;
    console.log("[snipes] poll cycle", { cycle });

    try {
      const snipes = await listActiveSnipes();
      for (const snipe of snipes) {
        try {
          const risk = await getTokenRisk(snipe.tokenAddress);
          await updateSnipe(snipe._id, {
            lastCheck: {
              at: new Date(),
              riskFlags: risk.flags || [],
              liquidityWarning: Boolean(risk.liquidityWarning),
              riskyWarning: Boolean(risk.riskyWarning)
            }
          });
        } catch (err) {
          console.warn("[snipes] item failure", { snipeId: snipe._id, error: safeErr(err) });
        }
      }

      const now = Date.now();
      if (now - lastMemLog > 60000) {
        lastMemLog = now;
        const m = process.memoryUsage();
        console.log("[mem]", { rssMB: Math.round(m.rss / 1e6), heapUsedMB: Math.round(m.heapUsed / 1e6) });
      }
    } catch (err) {
      console.warn("[snipes] poll failure", { error: safeErr(err) });
    }

    await sleep(Math.max(5000, cfg.SNIPE_POLL_MS || 15000));
  }
}

export function startSnipeMonitor() {
  if (running) return;
  running = true;
  timer = monitorLoop().catch((err) => {
    running = false;
    console.error("[snipes] monitor crashed", { error: safeErr(err) });
  });
}

export function stopSnipeMonitor() {
  running = false;
  return timer;
}

store.js.content:
import { ObjectId } from "mongodb";
import { getDb, stripImmutable } from "../lib/db.js";
import { safeErr } from "../lib/log.js";

const memory = {
  users: new Map(),
  wallets: new Map(),
  positions: new Map(),
  trades: new Map(),
  snipes: new Map()
};

export const DEFAULT_SETTINGS = {
  maxPercentPerTrade: 20,
  defaultSlippage: 1,
  defaultBuyAmount: 0.05,
  priorityFee: 0,
  bigBuyConfirmThreshold: 1,
  takeProfitPercent: 50,
  stopLossPercent: 20,
  riskWarnings: true
};

function id() {
  return new ObjectId().toString();
}

function userIdFromCtx(ctx) {
  return String(ctx.from?.id || "unknown");
}

export async function getOrCreateUser(ctx) {
  const telegramUserId = userIdFromCtx(ctx);
  const now = new Date();
  const mutable = stripImmutable({
    username: ctx.from?.username || "",
    firstName: ctx.from?.first_name || "",
    updatedAt: now
  });

  const db = getDb();
  if (!db) {
    const existing = memory.users.get(telegramUserId) || {
      _id: telegramUserId,
      telegramUserId,
      activeWalletId: "",
      settings: { ...DEFAULT_SETTINGS },
      createdAt: now
    };
    const next = { ...existing, ...mutable };
    memory.users.set(telegramUserId, next);
    return next;
  }

  try {
    await db.collection("users").updateOne(
      { telegramUserId },
      {
        $setOnInsert: {
          telegramUserId,
          activeWalletId: "",
          settings: { ...DEFAULT_SETTINGS },
          createdAt: now
        },
        $set: mutable
      },
      { upsert: true }
    );
    return await db.collection("users").findOne({ telegramUserId });
  } catch (err) {
    console.error("[db] write failed", { collection: "users", operation: "upsert", error: safeErr(err) });
    throw err;
  }
}

export async function updateUserSettings(userId, patch) {
  const now = new Date();
  const clean = stripImmutable(patch);
  const user = await getUserById(userId);
  const settings = { ...(user?.settings || DEFAULT_SETTINGS), ...clean };

  const db = getDb();
  if (!db) {
    memory.users.set(String(userId), { ...(user || {}), settings, updatedAt: now });
    return settings;
  }

  try {
    await db.collection("users").updateOne(
      { telegramUserId: String(userId) },
      { $set: { settings, updatedAt: now } }
    );
    return settings;
  } catch (err) {
    console.error("[db] write failed", { collection: "users", operation: "updateSettings", error: safeErr(err) });
    throw err;
  }
}

export async function getUserById(userId) {
  const db = getDb();
  if (!db) return memory.users.get(String(userId)) || null;
  try {
    return await db.collection("users").findOne({ telegramUserId: String(userId) });
  } catch (err) {
    console.error("[db] read failed", { collection: "users", operation: "findOne", error: safeErr(err) });
    return null;
  }
}

export async function createWallet(userId, wallet) {
  const now = new Date();
  const doc = {
    _id: id(),
    userId: String(userId),
    publicAddress: wallet.publicAddress,
    encryptedSecret: wallet.encryptedSecret || null,
    mode: wallet.mode,
    label: wallet.label || "Wallet",
    chainId: wallet.chainId,
    updatedAt: now
  };

  const db = getDb();
  if (!db) {
    memory.wallets.set(doc._id, doc);
    const user = memory.users.get(String(userId)) || { telegramUserId: String(userId), settings: { ...DEFAULT_SETTINGS }, createdAt: now };
    memory.users.set(String(userId), { ...user, activeWalletId: doc._id, updatedAt: now });
    return doc;
  }

  try {
    await db.collection("wallets").insertOne(doc);
    await db.collection("users").updateOne(
      { telegramUserId: String(userId) },
      { $set: { activeWalletId: doc._id, updatedAt: now } }
    );
    return doc;
  } catch (err) {
    console.error("[db] write failed", { collection: "wallets", operation: "insertOne", error: safeErr(err) });
    throw err;
  }
}

export async function listWallets(userId) {
  const db = getDb();
  if (!db) return [...memory.wallets.values()].filter((w) => w.userId === String(userId));
  try {
    return await db.collection("wallets").find({ userId: String(userId) }).sort({ }).toArray();
  } catch (err) {
    console.error("[db] read failed", { collection: "wallets", operation: "find", error: safeErr(err) });
    return [];
  }
}

export async function getActiveWallet(userId) {
  const user = await getUserById(userId);
  if (!user?.activeWalletId) return null;
  const db = getDb();
  if (!db) return memory.wallets.get(String(user.activeWalletId)) || null;
  try {
    return await db.collection("wallets").findOne({ _id: String(user.activeWalletId), userId: String(userId) });
  } catch (err) {
    console.error("[db] read failed", { collection: "wallets", operation: "findOne", error: safeErr(err) });
    return null;
  }
}

export async function createTradeIntent(doc) {
  const now = new Date();
  const trade = { _id: id(), ...stripImmutable(doc), createdAt: now, updatedAt: now };
  const db = getDb();
  if (!db) {
    memory.trades.set(trade._id, trade);
    return trade;
  }
  try {
    await db.collection("trades").insertOne(trade);
    return trade;
  } catch (err) {
    console.error("[db] write failed", { collection: "trades", operation: "insertOne", error: safeErr(err) });
    throw err;
  }
}

export async function getTrade(tradeId, userId) {
  const db = getDb();
  if (!db) {
    const t = memory.trades.get(String(tradeId));
    return t?.userId === String(userId) ? t : null;
  }
  try {
    return await db.collection("trades").findOne({ _id: String(tradeId), userId: String(userId) });
  } catch (err) {
    console.error("[db] read failed", { collection: "trades", operation: "findOne", error: safeErr(err) });
    return null;
  }
}

export async function updateTrade(tradeId, patch) {
  const now = new Date();
  const clean = stripImmutable({ ...patch, updatedAt: now });
  const db = getDb();
  if (!db) {
    const prev = memory.trades.get(String(tradeId)) || {};
    const next = { ...prev, ...clean };
    memory.trades.set(String(tradeId), next);
    return next;
  }
  try {
    await db.collection("trades").updateOne({ _id: String(tradeId) }, { $set: clean });
    return await db.collection("trades").findOne({ _id: String(tradeId) });
  } catch (err) {
    console.error("[db] write failed", { collection: "trades", operation: "updateOne", error: safeErr(err) });
    throw err;
  }
}

export async function listPositions(userId) {
  const db = getDb();
  if (!db) return [...memory.positions.values()].filter((p) => p.userId === String(userId));
  try {
    return await db.collection("positions").find({ userId: String(userId), status: { $ne: "closed" } }).sort({ updatedAt: -1 }).toArray();
  } catch (err) {
    console.error("[db] read failed", { collection: "positions", operation: "find", error: safeErr(err) });
    return [];
  }
}

export async function upsertPosition(position) {
  const now = new Date();
  const filter = {
    userId: String(position.userId),
    walletId: String(position.walletId || ""),
    tokenAddress: String(position.tokenAddress || "").toLowerCase()
  };
  const mutable = stripImmutable({ ...position, ...filter, updatedAt: now });
  const key = `${filter.userId}:${filter.walletId}:${filter.tokenAddress}`;
  const db = getDb();
  if (!db) {
    const prev = memory.positions.get(key) || { _id: id(), createdAt: now };
    const next = { ...prev, ...mutable };
    memory.positions.set(key, next);
    return next;
  }
  try {
    await db.collection("positions").updateOne(
      filter,
      { $setOnInsert: { _id: id(), createdAt: now }, $set: mutable },
      { upsert: true }
    );
    return await db.collection("positions").findOne(filter);
  } catch (err) {
    console.error("[db] write failed", { collection: "positions", operation: "upsert", error: safeErr(err) });
    throw err;
  }
}

export async function createSnipe(doc) {
  const now = new Date();
  const snipe = { _id: id(), ...stripImmutable(doc), status: doc.status || "active", createdAt: now, updatedAt: now };
  const db = getDb();
  if (!db) {
    memory.snipes.set(snipe._id, snipe);
    return snipe;
  }
  try {
    await db.collection("snipes").insertOne(snipe);
    return snipe;
  } catch (err) {
    console.error("[db] write failed", { collection: "snipes", operation: "insertOne", error: safeErr(err) });
    throw err;
  }
}

export async function listSnipes(userId, includeAll = false) {
  const query = { userId: String(userId) };
  if (!includeAll) query.status = { $in: ["active", "paused"] };
  const db = getDb();
  if (!db) {
    return [...memory.snipes.values()].filter((s) => s.userId === String(userId) && (includeAll || ["active", "paused"].includes(s.status)));
  }
  try {
    return await db.collection("snipes").find(query).sort({ updatedAt: -1 }).toArray();
  } catch (err) {
    console.error("[db] read failed", { collection: "snipes", operation: "find", error: safeErr(err) });
    return [];
  }
}

export async function listActiveSnipes() {
  const db = getDb();
  if (!db) return [...memory.snipes.values()].filter((s) => s.status === "active");
  try {
    return await db.collection("snipes").find({ status: "active" }).limit(500).toArray();
  } catch (err) {
    console.error("[db] read failed", { collection: "snipes", operation: "findActive", error: safeErr(err) });
    return [];
  }
}

export async function updateSnipe(snipeId, patch) {
  const clean = stripImmutable({ ...patch, updatedAt: new Date() });
  const db = getDb();
  if (!db) {
    const prev = memory.snipes.get(String(snipeId)) || {};
    const next = { ...prev, ...clean };
    memory.snipes.set(String(snipeId), next);
    return next;
  }
  try {
    await db.collection("snipes").updateOne({ _id: String(snipeId) }, { $set: clean });
    return await db.collection("snipes").findOne({ _id: String(snipeId) });
  } catch (err) {
    console.error("[db] write failed", { collection: "snipes", operation: "updateOne", error: safeErr(err) });
    throw err;
  }
}

